-- Enrichment marathon batch: Tube, Tube Archivist, Tuleap, Turso, Tuwunel, Tweek, TweetHunter, Twenty

-- ── Tube ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tube is a free, self-hosted, open-source video sharing platform written in Go that lets individuals and communities run their own censorship-free, YouTube-style video site.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tube Review: Self-Hosted Open-Source Video Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Tube is a free, open-source, self-hosted video sharing app written in Go with automatic transcoding, RSS feeds, and no ads or tracking.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tube is a free, open-source, self-hosted video sharing application written in the Go programming language. It is developed and maintained by James Mills (online handle prologic), a software engineer and open-source contributor also known for projects such as Yarn.social and Salty.im, and it was originally based on an earlier tube project created by developer Davy Wybiral. The project is hosted on Mills' self-managed Gitea instance at git.mills.io/prologic/tube and mirrored on GitHub. Tube is designed as a lightweight, YouTube-like alternative that individuals, hobbyists, and small communities can run on their own servers without censorship, ads, tracking, or the algorithmic recommendation systems found on mainstream platforms. Rather than relying on a traditional database, Tube stores video metadata as YAML files alongside the media, and it automatically transcodes uploaded footage to MP4 using H.264/AAC via FFmpeg. It generates thumbnails automatically, supports multiple video collections or libraries, exposes an RSS feed for each collection, and offers a minimal, JavaScript-light web interface that keeps resource usage low. Deployment options include prebuilt binaries for multiple platforms and an official Docker image, and the maintainer runs a public production instance at tube.mills.io on a Docker Swarm cluster to demonstrate real-world usage. Tube is released under the MIT license, making it entirely free to download, modify, and self-host with no subscription fees, seat limits, or vendor lock-in. Because it is a small, community-maintained open-source project rather than a funded company, it has no pricing plans, sales team, or SLA, and support is handled through the project repository and issue tracker. It is best suited for developers, self-hosting enthusiasts, and privacy-conscious communities who want direct control over their video hosting infrastructure, and it competes conceptually with other self-hosted video platforms such as PeerTube rather than with commercial platforms like YouTube or Vimeo.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4e301513-c3b6-4e23-8121-6625186cf446';

