-- ── Tube Archivist ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tube Archivist is a free, open-source, self-hosted media server that indexes, downloads, and organizes YouTube channel subscriptions so you can browse and watch your archive offline.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tube Archivist: Self-Hosted YouTube Archive Server$q$, seo_title),
  seo_meta_description = COALESCE($q$Tube Archivist is a free, open-source, self-hosted YouTube media server for downloading, indexing, and browsing channel subscriptions offline.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tube Archivist is a free and open-source, self-hosted media server purpose-built for archiving YouTube content. First released in September 2021, it is developed as a community open-source project hosted at github.com/tubearchivist and distributed under the GPL-3.0 license. The software lets users subscribe to YouTube channels, automatically download new videos using the yt-dlp downloader, and index each video's metadata (titles, descriptions, thumbnails, comments, and captions) into an Elasticsearch-backed search index, so the entire personal archive becomes fully searchable. A built-in web player lets users watch archived videos directly, track viewing history, and browse by channel or playlist, while browser extensions for Firefox and Chrome allow one-click archival of videos discovered while browsing YouTube normally. Tube Archivist is commonly deployed via Docker alongside companion services such as Elasticsearch and Redis, and it integrates with popular self-hosted media servers like Jellyfin and Plex so archived videos can be watched through those interfaces as well. As a fully open-source project with roughly 8,000-plus GitHub stars and dozens of contributors, Tube Archivist has no company behind it in the traditional sense; it is community maintained, accepts donations, and offers an optional paid membership tier through members.tubearchivist.com that unlocks real-time notifications and other perks to help fund ongoing development, but the core software itself remains free. It differs from general-purpose self-hosted video tools like Tube or PeerTube in that it is purpose-built specifically to mirror and preserve YouTube content for users worried about video deletion, channel removal, or losing access to content they rely on, making it popular within the self-hosting and digital-preservation communities alongside tools like yt-dlp.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd3725ed0-83b6-4344-b6e9-9cc03592d572';

