-- ── Tuleap ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tuleap is an open-source, all-in-one application lifecycle management (ALM) platform from French company Enalean, covering agile project management, requirements, testing, and DevOps traceability.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted Community Edition); paid cloud plans from EUR13/user/month$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Saint-Alban-Leysse, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Tuleap Review: Open-Source ALM and Agile Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Tuleap is an open-source ALM platform for agile project management, requirements traceability, and DevOps, built by French company Enalean.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tuleap is an open-source application lifecycle management (ALM) platform developed by Enalean, a software company founded in 2011 by Laurent Charles (CEO) and Manuel Vacelet (CTO) and headquartered in Saint-Alban-Leysse, France. Tuleap traces its lineage back to Codendi, an earlier forge tool with roots at Xerox, which Enalean forked and rebuilt into Tuleap under the GPLv2 open-source license. The platform is aimed at engineering and software teams that need to manage the full lifecycle of a project in one place, combining agile project management (Scrum, Kanban, and hybrid or SAFe-based methodologies), requirements management with full traceability, integrated test management, source control and CI/CD via Git, and program-level portfolio management, with particular strength in regulated or safety-critical industries that require ISO 26262, ASPICE, or CMMI compliance evidence. In 2026, Tuleap became part of the Dassault Systemes CATIA brand ecosystem, aimed at strengthening the connection between systems engineering and software development for industrial customers. Tuleap is available as a free, self-hostable open-source Community edition, as well as commercial cloud and on-premises editions with pricing that starts around EUR13 per user per month for a basic cloud plan, rising to roughly EUR23 to EUR25 per user per month for premium on-premises or cloud tiers with SSO, larger storage allowances, and dedicated support, with custom enterprise pricing for organizations needing dedicated infrastructure or specific hosting regions such as France, the EU, Switzerland, the UK, the US, or Canada. Tuleap differentiates itself from tools like Jira or Azure DevOps through its open-source core, strong data sovereignty options, and deep support for regulated engineering workflows, while Capterra and G2 users rate it around 4.3 to 4.5 out of 5.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '932248d2-07e2-4834-ad47-abd847ca7ad8';

