-- ── Turso ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Turso is a SQLite-compatible, edge-native database platform built on libSQL that lets developers spin up thousands of lightweight, low-latency databases for modern and AI-driven applications.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free (Free plan); Scaler plan from $24.92/month$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Turso Review: SQLite-Compatible Edge Database Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Turso is a SQLite-compatible edge database built on libSQL, offering low-latency, multi-tenant databases with free and usage-based pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Turso is a cloud-native, SQLite-compatible database platform built by the company of the same name, founded in 2021 by Glauber Costa and Pekka Enberg under the earlier name ChiselStrike before rebranding to Turso. The product is built on libSQL, an open-source, community-driven fork and Rust-based rewrite of SQLite that Turso maintains, which preserves full SQLite compatibility while adding features needed for distributed, multi-tenant, and edge-deployed applications. Turso's core pitch is enabling developers to create very large numbers of small, low-cost databases, sometimes one per user or tenant, rather than relying on a single large shared database instance, which suits multi-tenant SaaS applications, embedded and on-device use cases, and increasingly AI agent and RAG workloads thanks to native vector search support. Databases can run embedded on-device, in the browser via WebAssembly, or in Turso's managed cloud, with an always-on architecture designed to avoid cold starts, plus features like concurrent multi-writer support, Copy-on-Write database branching, and offline sync. Turso's pricing includes a free tier (100 databases, 5GB storage, 500 million monthly row reads, 10 million monthly row writes), a Developer plan around $4.99/month, a Scaler plan around $24.92/month with unlimited databases and usage-based overages, a Pro plan around $416.58/month, and custom Enterprise pricing. The company has raised early-stage funding, including a seed round, and operates as a small, distributed team of roughly a few dozen employees. Turso differentiates itself from traditional managed Postgres or MySQL providers, and from other SQLite-hosting competitors, through its emphasis on massive database multi-tenancy, edge replication, and SQLite's simplicity, positioning it as infrastructure for the age of AI agents and edge computing rather than a single centralized database server.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8f8c6456-68f6-4f02-bd51-cf48403d7a42';

