-- ── Tuwunel ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tuwunel is a free, open-source Matrix homeserver written in Rust, built as the official successor to conduwuit for scalable, self-hosted, spec-compliant Matrix chat deployments.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2025, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tuwunel Review: Rust Matrix Homeserver Successor to Conduwuit$q$, seo_title),
  seo_meta_description = COALESCE($q$Tuwunel is a free, open-source Matrix homeserver in Rust, the official successor to conduwuit, built for scalable self-hosted chat deployments.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tuwunel is a free, open-source Matrix protocol homeserver written entirely in Rust, created under the matrix-construct organization on GitHub with its first commits dating to February 2025. It is positioned as the official successor to conduwuit, a popular high-performance fork of the original Conduit Matrix homeserver, after the conduwuit project was discontinued; migrating an existing conduwuit deployment to Tuwunel is described by its developers as a straightforward binary swap. Tuwunel aims to be a highly available, horizontally scalable, specification-compliant Matrix homeserver capable of handling high-volume messaging with low latency, and independent 2026 benchmark testing reportedly showed it outperforming Synapse, Matrix's original reference homeserver implementation, in several test scenarios, in some configurations by a factor of over nine times. The project is released under the Apache License 2.0 and is developed by a small team of full-time contributors including x86pup, Jason Volk, and Timo Kosters, with institutional backing that reportedly includes sponsorship from the government of Switzerland, where the software is used in a citizen-facing deployment. Feature-wise, Tuwunel supports modern authentication standards including OAuth 2.0, OIDC, LDAP, and JWT, Matrix RTC for voice and video calling compatibility with Element Call, and an admin API compatible with Synapse's admin endpoints to ease migration for existing Matrix server operators. As with other Matrix homeserver software, Tuwunel is free to download and self-host, with no vendor licensing fees; organizations needing dedicated support or enterprise features work directly with the project's maintainers or sponsors rather than through a traditional SaaS pricing plan. It competes with other Matrix server implementations such as Synapse, Dendrite, and the community-driven Continuwuity fork, which also emerged after conduwuit's discontinuation.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '345a3674-eba8-4d0e-a817-1203b09a6953';

