-- ── Tweek ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tweek is a minimal, paper-planner-style weekly to-do list and calendar app that helps individuals organize tasks, notes, and calendar events in a clean weekly grid.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Premium from $5.99/month)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Riga, Latvia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tweek Review: Minimal Weekly Planner App and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Tweek is a minimal weekly to-do list and planner app with Google and Apple Calendar sync. See features, pricing, and how it compares to other planners.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tweek is a minimal, weekly-grid to-do list and planner application created by co-founder Alex Vasilevsky and launched in 2020, with the company reportedly based in Riga, Latvia and operating as a small, self-funded team of around five people. The product started as a simple spreadsheet-style planner modeled on old-school paper weekly planners and has since grown into a full web app and mobile app (available on iOS) that presents each week as a clean, seven-day grid for organizing tasks. Tweek's core interaction model centers on dragging and dropping tasks between days, a Someday column for unscheduled items, and a lightweight, distraction-free interface that deliberately avoids the complexity of full project management tools like Todoist, Asana, or Notion. Tweek offers a free plan that includes the core weekly grid, access to Tweek GPT (an AI assistant feature), up to three Someday columns, and up to two connected calendars. A Premium subscription, priced at $5.99 per month or $49.99 per year (with a 14-day free trial), unlocks Google Calendar and Apple Calendar two-way sync, subtasks, reminders, recurring tasks, file attachments, unlimited calendars and Someday columns, a monthly view, custom themes, and the ability to hide completed tasks. Tweek is built for individual users rather than teams, offering no enterprise or team pricing tiers, which distinguishes it from broader task-management platforms. It competes most directly with other minimalist weekly planners such as TeuxDeux, positioning itself around simplicity, a paper-like aesthetic, and calendar-first weekly planning rather than heavier project or task management feature sets.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0dd77a12-e3bc-4d46-ba35-97303cca0d1d';

