-- ── TweetHunter ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$TweetHunter is an all-in-one X (Twitter) growth tool offering AI tweet writing, scheduling, automation, and analytics to help creators and brands grow their following.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$49/month$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$TweetHunter Review: X (Twitter) Growth and Scheduling Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$TweetHunter is an all-in-one X growth tool with AI writing, scheduling, automation, and analytics. See features, pricing, and who owns it.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$TweetHunter is an all-in-one growth tool for X (formerly Twitter), combining content creation, scheduling, automation, and analytics to help creators, founders, and brands grow their following and engagement. It was founded in May 2021 by Tibo Louis-Lucas and Tom Jacquesson under their startup studio Pony Express, alongside a sister product for LinkedIn called Taplio. TweetHunter grew quickly as a bootstrapped SaaS product, reportedly reaching significant monthly recurring revenue within its first year, before Tibo Louis-Lucas and his co-founder sold both TweetHunter and Taplio to lempire (the company behind the cold outreach tool lemlist, headquartered in Paris, France) in an eight-figure acquisition completed around 2022 to 2023, with reported deal terms including an upfront payment plus an earn-out. Under lempire's ownership, TweetHunter continues to operate as a standalone product focused specifically on X growth. Its feature set includes a searchable library of more than two million viral tweets for inspiration, AI-powered tweet writing and rewriting tools, thread idea generators, a curated library of thousands of staff-picked tweets across multiple categories, a full scheduling system supporting tweets, threads, images, GIFs, and video, automation features like Auto DM (sending direct messages triggered by engagement) and Auto Plug (automatically replying to top-performing tweets with product links), and analytics covering follower growth, top tweets, and individual tweet performance, with shareable public statistics pages. TweetHunter is sold on a subscription basis with a 7-day free trial: a $49-per-month plan includes all core features except AI writing tools, while a $99-per-month plan adds the full AI writing suite, and both plans include a 30-day refund policy. The company reports being used by more than 5,600 X creators. TweetHunter's closest direct competitors include Typefully and Hypefury, other X-focused scheduling and growth tools.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '54c7cb92-5f47-43ad-bdf6-8b7349f90a2d';

