-- ── Twenty ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Twenty is an open-source CRM platform built for technical teams, offering a customizable, self-hostable alternative to Salesforce and HubSpot with a modern, spreadsheet-like interface.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); Cloud Pro from $9/user/month$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Twenty CRM Review: Open-Source Salesforce Alternative$q$, seo_title),
  seo_meta_description = COALESCE($q$Twenty is an open-source CRM for technical teams. Self-host free under AGPLv3 or use Twenty Cloud from $9/user/month. See features and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Twenty is an open-source customer relationship management (CRM) platform founded in 2023 by Charles Bochet, Thomas des Francs, and Felix Malfait, a team with roots in Paris, France that also went through Y Combinator's Summer 2023 batch and is registered as a public benefit corporation with a US entity in San Francisco. Twenty was built as a modern, developer-friendly alternative to proprietary CRMs like Salesforce and HubSpot, aiming to remove vendor lock-in and high licensing costs by making the entire product open source under the AGPLv3 license. The platform provides a customizable data model, spreadsheet-like record views, workflow automation, and a no-code interface for creating custom objects, fields, and views directly from Settings, alongside a developer-facing framework (including a Twenty SDK) for building deeper custom extensions, server-side logic, and React-based components. Twenty integrates AI-assisted development workflows, supporting tools like Claude, ChatGPT, and Cursor to help teams iterate on their CRM setup faster. Because it is AGPLv3 licensed, Twenty can be self-hosted for free with unlimited users and all core Pro-level features included, though organizations that build and redistribute a modified, hosted version of Twenty as their own product are required either to open-source those modifications or purchase a commercial license. For teams that prefer a managed deployment, Twenty offers a Cloud Pro plan at $9 per user per month (billed annually) and a Cloud Organization plan at $19 per user per month that adds SAML/OIDC single sign-on and row-level permissions. Twenty has raised approximately $5.5 million in funding, including a $5 million round announced in November 2024, and by 2026 the project had grown to roughly 44,000 to 50,000 GitHub stars, with reported customers or evaluators including large organizations such as the French government, Bayer, and PwC.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c6ed054f-8434-4025-8ef7-01e474837fea';

